class Solution {
public:
    int findBestValue(vector<int>& arr, int target) {
        int n = arr.size();
        sort(arr.begin(), arr.end());
        long long sum = 0;
        for (int i = 0; i < n; i++) {
            sum += arr[i];
        }
        long long diff = INT_MAX;
        int ans = arr[n - 1];
        for (int i = arr[0]; i <= arr[n - 1]; i++) {
            long long newSum = sum - (long long)arr[n - 1] + (long long)i;
            long long curDiff = abs(newSum - target);
            if (curDiff < diff) {
                diff = curDiff;
                ans = i;
            } else if (curDiff == diff && ans > i) {
                ans = i;
            }
        }
        return ans;
    }
};```
